export const GUIDE_BLOCKS: GuideBlock[] = [

  // ── 1. SİMÜLASYON OLUŞTURMA ──────────────────────────────────────────────
  { kind: 'h', text: { tr: 'I.  Simülasyon Oluşturma', en: 'I.  Creating a Simulation', de: 'I.  Simulation erstellen', fr: 'I.  Créer une simulation', ar: 'I.  إنشاء المحاكاة' } },
  { kind: 'sub', text: { tr: 'Temel Parametreler', en: 'Core Parameters', de: 'Kernparameter', fr: 'Paramètres fondamentaux', ar: 'المعاملات الأساسية' } },
  { kind: 'row', label: { tr: 'Simülasyon Adı', en: 'Simulation Name', de: 'Simulationsname', fr: 'Nom de la simulation', ar: 'اسم المحاكاة' }, value: { tr: 'Medeniyetinize anlamlı bir ad verin. Bu ad raporlarda, kontrol panelinde ve tüm ihracat dosyalarında kullanılır.', en: 'Give your civilization a meaningful name. It is used in reports, the dashboard and all export files.', de: 'Geben Sie Ihrer Zivilisation einen aussagekräftigen Namen. Er erscheint in Berichten, im Kontrollpanel und in allen Exportdateien.', fr: 'Donnez un nom significatif à votre civilisation. Il est utilisé dans les rapports, le tableau de bord et tous les fichiers exportés.', ar: 'امنح حضارتك اسماً ذا معنى. يُستخدم في التقارير ولوحة التحكم وجميع ملفات التصدير.' } },
  { kind: 'row', label: { tr: 'Enlem / Boylam', en: 'Latitude / Longitude', de: 'Breite / Länge', fr: 'Latitude / Longitude', ar: 'خط العرض / خط الطول' }, value: { tr: 'Başlangıç koordinatları; biyomu, iklimi, mevsim döngüsünü ve hastalık riskini doğrudan belirler. Tropikal bölgelerde sıtma riski artar; kutup bölgelerinde kaynak kıtlığı yaşanır.', en: 'Starting coordinates directly determine biome, climate, seasonal cycle and disease risk. Tropical regions increase malaria risk; polar regions face resource scarcity.', de: 'Die Startkoordinaten bestimmen direkt das Biom, das Klima, den Jahreszyklus und das Krankheitsrisiko. Tropische Regionen erhöhen das Malariarisiko; polare Regionen leiden unter Ressourcenknappheit.', fr: "Les coordonnées de départ déterminent directement le biome, le climat, le cycle saisonnier et le risque de maladie. Les régions tropicales augmentent le risque de paludisme ; les régions polaires souffrent de pénurie de ressources.", ar: 'تحدد إحداثيات البداية مباشرةً المنطقة الحيوية والمناخ ودورة المواسم وخطر المرض. تزيد المناطق الاستوائية من خطر الملاريا؛ وتعاني المناطق القطبية من شح الموارد.' } },

  { kind: 'sub', text: { tr: 'Kurucu Ayarları', en: 'Founder Configuration', de: 'Gründer-Konfiguration', fr: 'Configuration des fondateurs', ar: 'تهيئة المؤسسين' } },
  { kind: 'row', label: { tr: 'İsim & Yaş', en: 'Name & Age', de: 'Name & Alter', fr: 'Nom & Âge', ar: 'الاسم والعمر' }, value: { tr: 'Her kurucuya özel bir isim ve 16–60 arası başlangıç yaşı verilebilir. Yaş; üreme ömrünü, ilk neslin genetik çeşitliliğini ve ilk yıllardaki ölüm olasılığını etkiler.', en: 'Each founder can have a custom name and a starting age of 16–60. Age affects reproductive lifespan, first-generation genetic diversity and early mortality probability.', de: 'Jeder Gründer kann einen eigenen Namen und ein Startalter von 16–60 haben. Das Alter beeinflusst die Fortpflanzungslebensdauer, die genetische Vielfalt der ersten Generation und die frühe Sterblichkeitswahrscheinlichkeit.', fr: "Chaque fondateur peut avoir un nom personnalisé et un âge de départ de 16 à 60 ans. L'âge affecte la durée de vie reproductive, la diversité génétique de la première génération et la probabilité de mortalité précoce.", ar: 'يمكن منح كل مؤسس اسماً مخصصاً وعمر بداية يتراوح بين 16-60. يؤثر العمر في العمر الإنجابي والتنوع الجيني للجيل الأول واحتمالية الوفاة المبكرة.' } },
  { kind: 'row', label: { tr: 'Görünüş', en: 'Physical Appearance', de: 'Äußeres Erscheinungsbild', fr: 'Apparence physique', ar: 'المظهر الجسدي' }, value: { tr: 'Göz rengi, saç rengi ve ten tonu seçilebilir. Bu özellikler kalıtım yoluyla sonraki nesillere aktarılır ve nüfus içinde gözlemlenebilir fenotipik çeşitlilik oluşturur.', en: 'Eye colour, hair colour and skin tone can be selected. These traits are passed to subsequent generations through inheritance, creating observable phenotypic diversity within the population.', de: 'Augenfarbe, Haarfarbe und Hautton können gewählt werden. Diese Merkmale werden durch Vererbung an nachfolgende Generationen weitergegeben und erzeugen eine beobachtbare phänotypische Vielfalt in der Population.', fr: "La couleur des yeux, des cheveux et le teint peuvent être sélectionnés. Ces traits sont transmis aux générations suivantes par héritage, créant une diversité phénotypique observable au sein de la population.", ar: 'يمكن اختيار لون العيون ولون الشعر ودرجة لون البشرة. تنتقل هذه السمات بالوراثة إلى الأجيال التالية مما يخلق تنوعاً ظاهرياً قابلاً للملاحظة داخل المجتمع.' } },

  { kind: 'sub', text: { tr: 'Genetik Özellikler — 20 Parametre', en: 'Genetic Traits — 20 Parameters', de: 'Genetische Merkmale — 20 Parameter', fr: 'Traits génétiques — 20 paramètres', ar: 'السمات الجينية — 20 معاملاً' } },
  { kind: 'note', text: { tr: 'Her özellik 0–1 arasında bir değer alır ve kurucuların genomuna işlenir. Değerler nesiller boyunca mutasyon ve çevresel baskıyla değişebilir; başlangıç değerleri yalnızca kurucu neslini tanımlar.', en: "Each trait takes a value from 0–1 and is written into the founders' genomes. Values can shift over generations through mutation and environmental pressure; starting values define only the founding generation.", de: 'Jedes Merkmal nimmt einen Wert von 0–1 an und wird in das Genom der Gründer eingeschrieben. Werte können sich durch Mutation und Umweltdruck über Generationen hinweg verschieben; Anfangswerte definieren nur die Gründergeneration.', fr: 'Chaque trait prend une valeur de 0 à 1 et est gravé dans les génomes des fondateurs. Les valeurs peuvent évoluer au fil des générations par mutation et pression environnementale ; les valeurs initiales ne définissent que la génération fondatrice.', ar: 'تأخذ كل سمة قيمة من 0 إلى 1 وتُكتب في جينومات المؤسسين. يمكن أن تتحول القيم عبر الأجيال بفعل الطفرات والضغط البيئي؛ وتحدد القيم الابتدائية جيل المؤسسين فقط.' } },
  { kind: 'bullet', text: { tr: 'ZİHİN · BİLİŞSEL (4): Zeka — teknoloji ve keşif hızını yönlendirir. Merak — keşif, ticaret ağı ve astronomi gözlemlerini tetikler. Dil Yeteneği — dil evrimi ve fonem gelişimini belirler. Öğrenme Hızı — birey başına beceri kazanım süresini kısaltır.', en: 'MIND · COGNITIVE (4): Intelligence — drives technology and discovery speed. Curiosity — triggers exploration, trade networks and astronomy observations. Language Capacity — determines language evolution and phoneme development. Learning Rate — reduces skill acquisition time per individual.', de: 'GEIST · KOGNITIV (4): Intelligenz — treibt Technologie- und Entdeckungsrate an. Neugier — löst Erkundung, Handelsnetzwerke und Astronomiebeobachtungen aus. Sprachfähigkeit — bestimmt Sprachentwicklung und Phonementwicklung. Lernrate — reduziert Kompetenzerwerb pro Individuum.', fr: "ESPRIT · COGNITIF (4) : Intelligence — propulse la vitesse technologique et des découvertes. Curiosité — déclenche l'exploration, les réseaux commerciaux et les observations astronomiques. Capacité langagière — détermine l'évolution du langage et le développement phonémique. Taux d'apprentissage — réduit le temps d'acquisition des compétences par individu.", ar: 'العقل · المعرفي (4): الذكاء — يقود سرعة التقنية والاكتشاف. الفضول — يُطلق الاستكشاف وشبكات التجارة والمراقبة الفلكية. القدرة اللغوية — تحدد تطور اللغة ونمو الفونيمات. معدل التعلم — يُقلّص وقت اكتساب المهارات لكل فرد.' } },
  { kind: 'bullet', text: { tr: 'ZİHİN · KİŞİLİK (6): Disiplin — kaynak kullanım verimliliği. Öz Farkındalık — Theory of Mind gelişim temposu. Stres Direnci — travma sonrası psikolojik toparlanma. Risk Toleransı — av ve keşif cesareti. İnovasyon — teknoloji keşif ihtimal katsayısı. Sanat Duygusu — yeni sanat formlarının ortaya çıkış eşiği.', en: 'MIND · CHARACTER (6): Discipline — resource use efficiency. Self-Awareness — Theory of Mind development tempo. Stress Resilience — post-trauma psychological recovery. Risk Tolerance — hunting and exploration boldness. Innovation — technology discovery probability coefficient. Art Sense — threshold for new art forms to emerge.', de: 'GEIST · CHARAKTER (6): Disziplin — Ressourcennutzungseffizienz. Selbstwahrnehmung — Theory of Mind Entwicklungstempo. Stressresilienz — psychologische Erholung nach Trauma. Risikobereitschaft — Jagd- und Erkundungskühnheit. Innovation — Technologieentdeckungswahrscheinlichkeitskoeffizient. Kunstsinn — Schwelle für das Entstehen neuer Kunstformen.', fr: "ESPRIT · CARACTÈRE (6) : Discipline — efficacité d'utilisation des ressources. Conscience de soi — tempo de développement de la Théorie de l'esprit. Résilience au stress — récupération psychologique post-traumatique. Tolérance au risque — audace à la chasse et à l'exploration. Innovation — coefficient de probabilité de découverte technologique. Sens artistique — seuil d'émergence de nouvelles formes d'art.", ar: 'العقل · الشخصية (6): الانضباط — كفاءة استخدام الموارد. الوعي الذاتي — وتيرة تطور نظرية العقل. المرونة من الإجهاد — التعافي النفسي بعد الصدمة. تحمل المخاطر — جرأة الصيد والاستكشاف. الابتكار — معامل احتمالية اكتشاف التقنية. الحس الفني — عتبة ظهور أشكال فنية جديدة.' } },
  { kind: 'bullet', text: { tr: 'SOSYAL (5): Empati — grup içi uyum ve ittifak gücü. Sosyal Bağ — gruba katılma ve grup kurma eğilimi. Saldırganlık — gruplar arası çatışma olasılığı. İşbirliği — ticaret frekansı ve ortak kaynak yönetimi. Liderlik Eğilimi — hiyerarşi hızı ve lider kalıcılığı.', en: 'SOCIAL (5): Empathy — intra-group cohesion and alliance strength. Social Bonding — tendency to join or form groups. Aggression — inter-group conflict probability. Cooperation — trade frequency and shared resource management. Leadership — hierarchy speed and leader tenure.', de: 'SOZIAL (5): Empathie — gruppeninterne Kohäsion und Allianzstärke. Soziale Bindung — Neigung zur Gruppen joining oder -bildung. Aggression — Wahrscheinlichkeit von Konflikten zwischen Gruppen. Kooperation — Handelshäufigkeit und gemeinsame Ressourcenverwaltung. Führung — Hierarchiegeschwindigkeit und Führungsdauer.', fr: "SOCIAL (5) : Empathie — cohésion intragroupale et force des alliances. Lien social — tendance à rejoindre ou former des groupes. Agressivité — probabilité de conflits intergroupes. Coopération — fréquence des échanges et gestion partagée des ressources. Leadership — vitesse de hiérarchisation et durée du mandat.", ar: 'الاجتماعي (5): التعاطف — تماسك المجموعة الداخلي وقوة التحالف. الترابط الاجتماعي — الميل للانضمام إلى المجموعات أو تكوينها. العدوانية — احتمالية الصراع بين المجموعات. التعاون — تكرار التجارة وإدارة الموارد المشتركة. القيادة — سرعة التسلسل الهرمي وفترة القيادة.' } },
  { kind: 'bullet', text: { tr: 'BEDEN (5): Fiziksel Güç — av başarısı ve liderlik rekabeti sonucu. Dayanıklılık — hastalık/yaralanma ölüm riski ve uzun yolculuk kapasitesi. Bağışıklık — patojen direnci ve salgın ölüm oranı. Üreme Dürtüsü — doğurganlık oranı ve nüfus büyüme hızı. Uzun Ömür — bireyin beklenen yaşam süresi tavanı.', en: 'BODY (5): Physical Strength — hunt success rate and leadership competition outcome. Endurance — disease/injury mortality risk and long-journey capacity. Immunity — pathogen resistance and epidemic death rate. Fertility — birth rate and population growth speed. Longevity — expected lifespan ceiling per individual.', de: 'KÖRPER (5): Körperkraft — Jagderfolgsrate und Führungskonkurrenzausgang. Ausdauer — Krankheits-/Verletzungssterblichkeitsrisiko und Langstreckenkapazität. Immunität — Pathogenresistenz und Epidemiesterblichkeitsrate. Fruchtbarkeit — Geburtenrate und Bevölkerungswachstumsgeschwindigkeit. Langlebigkeit — erwartete Lebenserwartungsgrenze pro Individuum.', fr: "CORPS (5) : Force physique — taux de réussite à la chasse et résultat de la compétition pour le leadership. Endurance — risque de mortalité maladie/blessure et capacité pour les longs voyages. Immunité — résistance aux pathogènes et taux de mortalité épidémique. Fertilité — taux de natalité et vitesse de croissance démographique. Longévité — plafond d'espérance de vie par individu.", ar: 'الجسد (5): القوة الجسدية — معدل نجاح الصيد ونتيجة منافسة القيادة. التحمل — خطر وفاة الأمراض/الإصابات وقدرة الرحلات الطويلة. المناعة — مقاومة مسببات الأمراض ومعدل وفيات الوبائيات. الخصوبة — معدل الولادة وسرعة نمو السكان. طول العمر — سقف العمر المتوقع لكل فرد.' } },

  // ── 2. ANA EKRAN ──────────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'II.  Ana Ekran & Harita', en: 'II.  Main Screen & Map', de: 'II.  Hauptbildschirm & Karte', fr: 'II.  Écran principal & Carte', ar: 'II.  الشاشة الرئيسية والخريطة' } },
  { kind: 'sub', text: { tr: '3B Dünya Haritası', en: '3D World Map', de: '3D-Weltkarte', fr: 'Carte du monde 3D', ar: 'خريطة العالم ثلاثية الأبعاد' } },
  { kind: 'bullet', text: { tr: 'Her ışık noktası bir bireydir. Sarı = kurucu, mavi = erkek, pembe = kadın. Bir noktaya tıkladığınızda o bireyin detay kartı açılır; isim, yaş, bilinç düzeyi, iç ses, sağlık ve aile bağlarını görebilirsiniz.', en: "Each light point is an individual. Yellow = founder, blue = male, pink = female. Clicking a point opens the individual's detail card showing name, age, consciousness level, inner voice, health and family links.", de: 'Jeder Lichtpunkt ist ein Individuum. Gelb = Gründer, Blau = männlich, Rosa = weiblich. Ein Klick auf einen Punkt öffnet die Detailkarte des Individuums mit Name, Alter, Bewusstseinsstufe, innerer Stimme, Gesundheit und Familienbindungen.', fr: "Chaque point lumineux est un individu. Jaune = fondateur, bleu = homme, rose = femme. Un clic ouvre la fiche de détail montrant le nom, l'âge, le niveau de conscience, la voix intérieure, la santé et les liens familiaux.", ar: 'كل نقطة ضوئية تمثل فرداً. أصفر = المؤسس، أزرق = ذكر، وردي = أنثى. النقر يفتح بطاقة التفاصيل مع الاسم والعمر ومستوى الوعي والصوت الداخلي والصحة وروابط الأسرة.' } },
  { kind: 'bullet', text: { tr: 'Harita üzerinde biyom, sıcaklık, besin bolluğu ve su bolluğu göstergeleri canlı güncellenir. Kırmızı uyarılar kritik kaynak kıtlığını; sarı uyarılar orta düzey baskıyı işaret eder.', en: 'Biome, temperature, food and water abundance indicators update live on the map. Red alerts indicate critical resource scarcity; yellow alerts signal moderate pressure.', de: 'Biom-, Temperatur-, Nahrungs- und Wassermengenindikatoren werden live auf der Karte aktualisiert. Rote Warnungen signalisieren kritische Ressourcenknappheit; gelbe Warnungen mäßigen Druck.', fr: "Les indicateurs de biome, température, nourriture et eau se mettent à jour en direct. Les alertes rouges signalent une pénurie critique ; les alertes jaunes une pression modérée.", ar: 'تتحدث مؤشرات المنطقة الحيوية ودرجة الحرارة ووفرة الغذاء والماء مباشرةً. التحذيرات الحمراء تشير إلى شح الموارد الحرج؛ والصفراء تشير إلى ضغط معتدل.' } },
  { kind: 'sub', text: { tr: 'Üst Bilgi Şeridi', en: 'Top Status Bar', de: 'Obere Statusleiste', fr: 'Barre de statut supérieure', ar: 'شريط الحالة العلوي' } },
  { kind: 'bullet', text: { tr: 'Yıl, gün, toplam nüfus, mutluluk yüzdesi, ortalama bilinç skoru ve aktif dil evresi anlık gösterilir. WARP aktifken hedef yıl göstergesi sarı renkte belirir ve ilerleme takip edilebilir.', en: 'Year, day, total population, happiness percentage, average consciousness score and active language stage are shown in real time. When WARP is active, the target year indicator turns yellow and progress can be monitored.', de: 'Jahr, Tag, Gesamtbevölkerung, Glücksprozentsatz, durchschnittlicher Bewusstseinswert und aktive Sprachstufe werden in Echtzeit angezeigt. Bei aktivem WARP wird der Zieljahrindikator gelb und der Fortschritt kann verfolgt werden.', fr: "L'année, le jour, la population totale, le pourcentage de bonheur, le score moyen de conscience et le stade linguistique actif sont affichés en temps réel. Lorsque le WARP est actif, l'indicateur d'année cible devient jaune.", ar: 'تُعرض السنة واليوم وإجمالي السكان ونسبة السعادة ومتوسط درجة الوعي ومرحلة اللغة النشطة في الوقت الفعلي. عند تنشيط WARP يتحول مؤشر السنة المستهدفة إلى اللون الأصفر.' } },

  // ── 3. KONTROLLER ─────────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'III.  Simülasyon Kontrolleri', en: 'III.  Simulation Controls', de: 'III.  Simulationssteuerung', fr: 'III.  Contrôles de simulation', ar: 'III.  عناصر التحكم في المحاكاة' } },
  { kind: 'row', label: { tr: 'Başlat / Durdur', en: 'Start / Pause', de: 'Start / Pause', fr: 'Démarrer / Pause', ar: 'تشغيل / إيقاف مؤقت' }, value: { tr: 'Simülasyonu çalıştırır veya duraklatır. Duraklatma anında tüm motor durumu otomatik olarak kaydedilir; veri kaybı yaşanmaz.', en: 'Runs or pauses the simulation. On pause, the entire engine state is automatically saved; no data is lost.', de: 'Startet oder pausiert die Simulation. Beim Pausieren wird der gesamte Engine-Zustand automatisch gespeichert; es gehen keine Daten verloren.', fr: "Lance ou met en pause la simulation. En pause, l'état complet du moteur est automatiquement sauvegardé ; aucune donnée n'est perdue.", ar: 'يشغّل المحاكاة أو يوقفها مؤقتاً. عند الإيقاف يتم حفظ حالة المحرك بالكامل تلقائياً دون فقدان أي بيانات.' } },
  { kind: 'row', label: { tr: 'Simülasyon Hızı', en: 'Simulation Speed', de: 'Simulationsgeschwindigkeit', fr: 'Vitesse de simulation', ar: 'سرعة المحاكاة' }, value: { tr: 'Dört hazır kademe (×1, ×5, ×20, ×100) arasında geçiş yapın ya da hız alanına istediğiniz herhangi bir tam sayıyı girerek özel bir çarpan belirleyin. ×1 gerçek zamanlı gözlem için, ×20–×100 arası hızlı medeniyet gelişimi için, çok yüksek özel değerler ise yüzyıllar arasındaki geçişler için idealdir.', en: 'Switch between four presets (×1, ×5, ×20, ×100) or enter any custom integer directly into the speed field to set your own multiplier. ×1 is ideal for real-time observation, ×20–×100 for rapid civilisation development, and very high custom values for century-spanning jumps.', de: 'Wechseln Sie zwischen vier Voreinstellungen (×1, ×5, ×20, ×100) oder geben Sie direkt eine beliebige ganze Zahl in das Geschwindigkeitsfeld ein, um Ihren eigenen Multiplikator festzulegen. ×1 ist ideal für die Echtzeit-Beobachtung, ×20–×100 für schnelle Zivilisationsentwicklung und sehr hohe benutzerdefinierte Werte für jahrhundertübergreifende Sprünge.', fr: "Basculez entre quatre préréglages (×1, ×5, ×20, ×100) ou saisissez directement n'importe quel entier dans le champ de vitesse pour définir votre propre multiplicateur. ×1 est idéal pour l'observation en temps réel, ×20–×100 pour un développement civilisationnel rapide, et des valeurs personnalisées très élevées pour des sauts de plusieurs siècles.", ar: 'بدّل بين أربعة إعدادات مسبقة (×1، ×5، ×20، ×100) أو أدخل أي عدد صحيح مباشرةً في حقل السرعة لتعيين مضاعفك الخاص. ×1 مثالي للمراقبة الفورية، و×20–×100 للتطور الحضاري السريع، والقيم المخصصة العالية جداً لقفزات عبر القرون.' } },
  { kind: 'row', label: { tr: 'IŞINIL GİT — Warp', en: 'WARP TO — Fast-Forward', de: 'WARP ZU — Schnellvorlauf', fr: 'WARP VERS — Avance rapide', ar: 'قفز إلى — تقديم سريع' }, value: { tr: 'Bir hedef yıl girerek simülasyonu o yıla ışınlayın. Warp aktifken tüm motorlar (biyoloji, sosyal, teknoloji, çevre) arka planda azami hızda paralel olarak çalışır. İptal etmek için "WARP AKTİF" düğmesine tıklayın.', en: 'Enter a target year to fast-forward the simulation to that point. While warping, all engines (biology, social, technology, environment) run in parallel at maximum speed in the background. Click "WARPING" to cancel.', de: 'Geben Sie ein Zieljahr ein, um die Simulation schnell zu diesem Zeitpunkt vorzuspulen. Während des Warps laufen alle Engines (Biologie, Soziales, Technologie, Umwelt) parallel mit maximaler Geschwindigkeit im Hintergrund. Klicken Sie auf "WARP AKTIV", um abzubrechen.', fr: "Saisissez une année cible pour faire avancer rapidement la simulation jusqu'à ce point. Pendant le warp, tous les moteurs (biologie, social, technologie, environnement) fonctionnent en parallèle à vitesse maximale en arrière-plan. Cliquez sur « WARP ACTIF » pour annuler.", ar: 'أدخل سنة مستهدفة للتقديم السريع للمحاكاة إلى تلك النقطة. أثناء القفز تعمل جميع المحركات (البيولوجيا والاجتماعي والتكنولوجيا والبيئة) بالتوازي بأقصى سرعة في الخلفية. انقر "WARP نشط" للإلغاء.' } },
  { kind: 'row', label: { tr: 'Menü', en: 'Menu', de: 'Menü', fr: 'Menu', ar: 'القائمة' }, value: { tr: 'Kullanım kılavuzu, dil seçenekleri, proje bilgisi ve iletişim sayfalarına erişim sağlar.', en: 'Provides access to the user guide, language options, project information and contact pages.', de: 'Bietet Zugang zu Benutzerhandbuch, Sprachoptionen, Projektinformationen und Kontaktseiten.', fr: "Donne accès au guide d'utilisation, aux options de langue, aux informations sur le projet et aux pages de contact.", ar: 'يوفر الوصول إلى دليل المستخدم وخيارات اللغة ومعلومات المشروع وصفحات التواصل.' } },

  // ── 4. PANELLER ───────────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'IV.  Analiz Panelleri', en: 'IV.  Analysis Panels', de: 'IV.  Analyse-Panels', fr: 'IV.  Panneaux d\'analyse', ar: 'IV.  لوحات التحليل' } },
  { kind: 'note', text: { tr: 'Tüm paneller sol kenar çubuğundan açılır ve simülasyon duraklatılmış olsa bile canlı tick akışıyla güncellenen en güncel verileri gösterir.', en: 'All panels open from the left sidebar and display the most current data updated with the live tick stream, even when the simulation is paused.', de: 'Alle Panels öffnen sich über die linke Seitenleiste und zeigen die aktuellsten Daten, die mit dem Live-Tick-Stream aktualisiert werden, auch wenn die Simulation pausiert ist.', fr: "Tous les panneaux s'ouvrent depuis la barre latérale gauche et affichent les données les plus récentes mises à jour avec le flux de ticks en direct, même lorsque la simulation est en pause.", ar: 'تُفتح جميع اللوحات من الشريط الجانبي الأيسر وتعرض أحدث البيانات المحدّثة مع تدفق التكات الحي حتى عند إيقاف المحاكاة مؤقتاً.' } },

  { kind: 'sub', text: { tr: 'Nüfus & Demografi', en: 'Population & Demographics', de: 'Bevölkerung & Demografie', fr: 'Population & Démographie', ar: 'السكان والديموغرافيا' } },
  { kind: 'row', label: { tr: 'Nüfus', en: 'Population', de: 'Bevölkerung', fr: 'Population', ar: 'السكان' }, value: { tr: 'Yaşayan bireylerin tam listesi. Her bireye tıklandığında isim, yaş, cinsiyet, bilinç düzeyi, aile bağları, iç ses düşünceleri, kişilik özellikleri, sağlık durumu ve yaşam hikayesi görüntülenir.', en: "Complete list of living individuals. Clicking any person displays name, age, sex, consciousness level, family links, inner voice thoughts, personality traits, health status and life story.", de: 'Vollständige Liste der lebenden Individuen. Ein Klick auf eine Person zeigt Name, Alter, Geschlecht, Bewusstseinsstufe, Familienbindungen, innere Stimme, Persönlichkeitsmerkmale, Gesundheitszustand und Lebensgeschichte.', fr: "Liste complète des individus vivants. Cliquer sur une personne affiche le nom, l'âge, le sexe, le niveau de conscience, les liens familiaux, les pensées de la voix intérieure, les traits de personnalité, l'état de santé et l'histoire de vie.", ar: 'القائمة الكاملة للأفراد الأحياء. النقر على أي شخص يُظهر الاسم والعمر والجنس ومستوى الوعي وروابط الأسرة وأفكار الصوت الداخلي وسمات الشخصية والحالة الصحية وقصة الحياة.' } },
  { kind: 'row', label: { tr: 'Nüfus Piramidi', en: 'Population Pyramid', de: 'Bevölkerungspyramide', fr: 'Pyramide des âges', ar: 'هرم السكان' }, value: { tr: 'Yaşa ve cinsiyete göre nüfus dağılımını yatay çubuk grafik olarak görselleştirir. Erkek sol, kadın sağ tarafta yer alır; cinsiyet oranı ve toplam sayılar özet olarak sunulur.', en: 'Visualises population distribution by age and sex as a horizontal bar chart. Males appear on the left, females on the right; sex ratio and total counts are summarised.', de: 'Visualisiert die Bevölkerungsverteilung nach Alter und Geschlecht als horizontales Balkendiagramm. Männer links, Frauen rechts; Geschlechterverhältnis und Gesamtzahlen werden zusammengefasst.', fr: 'Visualise la répartition de la population par âge et sexe sous forme de graphique à barres horizontales. Les hommes à gauche, les femmes à droite ; le ratio des sexes et les totaux sont résumés.', ar: 'يُصوّر توزيع السكان حسب العمر والجنس كمخطط شريطي أفقي. الذكور على اليسار والإناث على اليمين مع ملخص نسبة الجنس والأعداد الإجمالية.' } },
  { kind: 'row', label: { tr: 'Soy Ağacı', en: 'Genealogy', de: 'Stammbaum', fr: 'Généalogie', ar: 'شجرة الأنساب' }, value: { tr: 'Her kurucudan başlayarak dört nesle kadar aile ağacını görselleştirir. Erkek ve kadın soyu farklı renklerle ayrıştırılır; bireye tıklanarak profil detayı incelenebilir.', en: 'Visualises the family tree up to four generations from each founder. Male and female lineages are colour-coded; click any individual to inspect their profile.', de: 'Visualisiert den Familienstammbaum bis zu vier Generationen ab jedem Gründer. Männliche und weibliche Linien sind farbkodiert; klicken Sie auf ein Individuum, um sein Profil zu inspizieren.', fr: "Visualise l'arbre généalogique jusqu'à quatre générations à partir de chaque fondateur. Les lignées masculines et féminines sont codées par couleur ; cliquez sur un individu pour inspecter son profil.", ar: 'يُصوّر شجرة العائلة حتى أربعة أجيال من كل مؤسس. الخطوط الذكورية والأنثوية مرمّزة بالألوان؛ انقر على أي فرد لفحص ملفه الشخصي.' } },

  { kind: 'sub', text: { tr: 'Bilim & Keşif', en: 'Science & Discovery', de: 'Wissenschaft & Entdeckung', fr: 'Science & Découverte', ar: 'العلم والاكتشاف' } },
  { kind: 'row', label: { tr: 'Teknoloji', en: 'Technology', de: 'Technologie', fr: 'Technologie', ar: 'التكنولوجيا' }, value: { tr: 'Beş kademeli teknoloji ağacını ve tüm keşifleri listeler. Her keşfin kim tarafından, kaçıncı yılda, hangi yaş ve merak düzeyiyle gerçekleştiği kayıt altındadır.', en: 'Lists the five-tier technology tree and all discoveries. Each discovery records who made it, in which year, at what age and curiosity level.', de: 'Listet den fünfstufigen Technologiebaum und alle Entdeckungen auf. Jede Entdeckung verzeichnet, wer sie gemacht hat, in welchem Jahr, in welchem Alter und mit welchem Neugierdeniveau.', fr: "Liste l'arbre technologique à cinq niveaux et toutes les découvertes. Chaque découverte enregistre qui l'a faite, en quelle année, à quel âge et niveau de curiosité.", ar: 'يسرد شجرة التكنولوجيا ذات الخمسة مستويات وجميع الاكتشافات. تُسجّل كل اكتشاف من اكتشفه وفي أي عام وبأي عمر ومستوى فضول.' } },
  { kind: 'row', label: { tr: 'Astronomi', en: 'Astronomy', de: 'Astronomie', fr: 'Astronomie', ar: 'الفلك' }, value: { tr: 'Beş bilgi kademesini izler: Ay Takibi → Mevsim Takvimi → Yıldız Haritası → Tutulma Tahmini → Gezegen Modeli. Gözlemlenen gök olayları ve her kademe için gereken zeka, FOXP2 ve teknoloji eşikleri gösterilir.', en: 'Tracks five knowledge tiers: Lunar Tracking → Seasonal Calendar → Star Map → Eclipse Prediction → Planetary Model. Shows observed celestial events and the intelligence, FOXP2 and technology thresholds required for each tier.', de: 'Verfolgt fünf Wissensstufen: Mondverfolgung → Saisonkalender → Sternenkarte → Finsternisvorhersage → Planetenmodell. Zeigt beobachtete Himmelsereignisse und die Intelligenz-, FOXP2- und Technologieschwellen für jede Stufe.', fr: "Suit cinq niveaux de connaissance : Suivi lunaire → Calendrier saisonnier → Carte stellaire → Prédiction d'éclipse → Modèle planétaire. Affiche les événements célestes observés et les seuils d'intelligence, FOXP2 et technologie pour chaque niveau.", ar: 'يتتبع خمسة مستويات للمعرفة: تتبع القمر ← التقويم الموسمي ← خريطة النجوم ← التنبؤ بالكسوف ← نموذج الكواكب. يعرض الأحداث السماوية المرصودة وحدود الذكاء وFOXP2 والتكنولوجيا المطلوبة لكل مستوى.' } },
  { kind: 'row', label: { tr: 'Epigenetik', en: 'Epigenetics', de: 'Epigenetik', fr: 'Épigénétique', ar: 'علم الجينات اللاجينية' }, value: { tr: 'Sekiz genetik lokus üzerindeki metilasyon yüzdelerini ve kuşaklar arası kalıtım oranlarını gösterir. Epigenetik yaş, kronolojik yaştan farklılık gösterebilir ve bu fark nüfus sağlığının güçlü bir göstergesidir.', en: 'Shows methylation percentages across eight genetic loci and transgenerational heritability rates. Epigenetic age can differ from chronological age; this gap is a strong indicator of population health.', de: 'Zeigt Methylierungsprozentsätze über acht Genloci und transgenerationale Erblichkeitsraten. Das epigenetische Alter kann vom chronologischen Alter abweichen; diese Differenz ist ein starker Indikator für die Bevölkerungsgesundheit.', fr: "Affiche les pourcentages de méthylation sur huit loci génétiques et les taux d'héritabilité transgénérationnelle. L'âge épigénétique peut différer de l'âge chronologique ; cet écart est un indicateur fort de la santé de la population.", ar: 'يعرض نسب الميثيلة عبر ثمانية مواقع جينية ومعدلات الوراثة عبر الأجيال. قد يختلف العمر اللاجيني عن العمر الزمني؛ وهذا الفارق مؤشر قوي على صحة السكان.' } },

  { kind: 'sub', text: { tr: 'Kültür & Sanat', en: 'Culture & Art', de: 'Kultur & Kunst', fr: 'Culture & Art', ar: 'الثقافة والفن' } },
  { kind: 'row', label: { tr: 'Kültür', en: 'Culture', de: 'Kultur', fr: 'Culture', ar: 'الثقافة' }, value: { tr: 'Kültürel mem sayısını ve beş gelişim kademesini görselleştirir. Kültürel gelişim olay akışı canlı takip edilebilir; her yeni mem hangi bireyden ve hangi yıldan kaynaklandığı bilgisiyle kaydedilir.', en: 'Visualises cultural meme count and five development stages. The cultural event stream can be followed live; each new meme is recorded with the individual and year it originated from.', de: 'Visualisiert die Anzahl kultureller Meme und fünf Entwicklungsstufen. Der kulturelle Ereignisstrom kann live verfolgt werden; jedes neue Mem wird mit dem Individuum und Jahr seines Ursprungs aufgezeichnet.', fr: "Visualise le nombre de mèmes culturels et cinq stades de développement. Le flux d'événements culturels peut être suivi en direct ; chaque nouveau mème est enregistré avec l'individu et l'année d'où il provient.", ar: 'يُصوّر عدد الميمات الثقافية وخمس مراحل تطور. يمكن متابعة تدفق الأحداث الثقافية مباشرةً؛ وتُسجّل كل ميمة جديدة مع الفرد والسنة التي نشأت منها.' } },
  { kind: 'row', label: { tr: 'Sanat', en: 'Art', de: 'Kunst', fr: 'Art', ar: 'الفن' }, value: { tr: '12 sanat formunu (görsel, müzik, anlatı kategorileri) listeler. Her formun keşfi için gereken minimum besin fazlası, sanat duygusu skoru ve teknik ön koşullar ayrıntılı olarak gösterilir.', en: 'Lists 12 art forms across visual, music and narrative categories. The minimum food surplus, art sense score and technical prerequisites required to discover each form are shown in detail.', de: 'Listet 12 Kunstformen in visuellen, Musik- und Erzählkategorien auf. Der minimale Nahrungsüberschuss, der Kunstsinns-Score und die technischen Voraussetzungen für die Entdeckung jeder Form werden detailliert gezeigt.', fr: "Liste 12 formes d'art dans les catégories visuel, musique et narratif. L'excédent alimentaire minimum, le score du sens artistique et les prérequis techniques pour découvrir chaque forme sont affichés en détail.", ar: 'يسرد 12 شكلاً فنياً عبر فئات بصرية وموسيقية وسردية. يُعرض الحد الأدنى لفائض الغذاء ودرجة الحس الفني والمتطلبات التقنية اللازمة لاكتشاف كل شكل بالتفصيل.' } },
  { kind: 'row', label: { tr: 'İnanç', en: 'Belief Systems', de: 'Glaubenssysteme', fr: 'Systèmes de croyances', ar: 'أنظمة المعتقدات' }, value: { tr: 'İnanç sistemi arketiplerini ve ortaya çıkış koşullarını gösterir. İnanç oluşumu; dindarlık geni, kaygı düzeyi ve çevresel stres eşiklerine bağlıdır. Ritüel olay günlüğü arşivlenebilir.', en: 'Shows belief system archetypes and emergence conditions. Belief formation depends on the religiosity gene, anxiety level and environmental stress thresholds. The ritual event log can be archived.', de: 'Zeigt Glaubenssystem-Archetypen und Entstehungsbedingungen. Die Glaubensbildung hängt vom Religiositätsgen, dem Angstlevel und Umweltstressschwellen ab. Das Ritualeventlog kann archiviert werden.', fr: "Affiche les archétypes de systèmes de croyances et les conditions d'émergence. La formation des croyances dépend du gène de religiosité, du niveau d'anxiété et des seuils de stress environnemental. Le journal des rituels peut être archivé.", ar: 'يعرض أنماط نظام المعتقدات وشروط الظهور. يعتمد تكوّن المعتقد على جين التديّن ومستوى القلق وحدود الإجهاد البيئي. يمكن أرشفة سجل أحداث الطقوس.' } },
  { kind: 'row', label: { tr: 'Dil', en: 'Language', de: 'Sprache', fr: 'Langage', ar: 'اللغة' }, value: { tr: 'Altı dil evrim kademesini, sesgrup gelişimini (ünsüzler, ünlüler, yüzey biçimleri) ve diyalekt ayrışmasını izler. Dil olayları kategoriye göre filtrelenebilir ve arşivlenebilir.', en: 'Tracks six language evolution stages, phonology development (consonants, vowels, surface forms) and dialect divergence. Language events can be filtered by category and archived.', de: 'Verfolgt sechs Sprachentwicklungsstufen, Phonologieentwicklung (Konsonanten, Vokale, Oberflächenformen) und Dialektdivergenz. Sprachereignisse können nach Kategorie gefiltert und archiviert werden.', fr: "Suit six stades d'évolution du langage, le développement phonologique (consonnes, voyelles, formes de surface) et la divergence dialectale. Les événements linguistiques peuvent être filtrés par catégorie et archivés.", ar: 'يتتبع ست مراحل لتطور اللغة وتطور علم الأصوات (الصوامت والحركات والأشكال السطحية) وتشعب اللهجات. يمكن تصفية أحداث اللغة حسب الفئة وأرشفتها.' } },
  { kind: 'row', label: { tr: 'Mimari', en: 'Architecture', de: 'Architektur', fr: 'Architecture', ar: 'العمارة' }, value: { tr: 'İnşa edilen toplam yapı sayısını ve dört kademe yapı tipini (doğal sığınak, basit yapı, kalıcı yapı, kentsel yapı) gösterir. Her inşaat olayı tarih, inşaatçı ve konum bilgisiyle günlüğe kaydedilir.', en: 'Shows total structures built and four structure tiers (natural shelter, simple structure, permanent structure, urban structure). Each construction event is logged with date, builder and location.', de: 'Zeigt die Gesamtzahl gebauter Strukturen und vier Strukturstufen (natürliches Schutzgebiet, einfache Struktur, dauerhafte Struktur, städtische Struktur). Jedes Bauereignis wird mit Datum, Erbauer und Standort protokolliert.', fr: "Affiche le nombre total de structures construites et quatre niveaux (abri naturel, structure simple, structure permanente, structure urbaine). Chaque événement de construction est consigné avec la date, le constructeur et l'emplacement.", ar: 'يعرض العدد الإجمالي للمنشآت المبنية وأربعة مستويات (مأوى طبيعي، منشأة بسيطة، منشأة دائمة، منشأة حضرية). يُسجّل كل حدث بناء مع التاريخ والمنشئ والموقع.' } },

  { kind: 'sub', text: { tr: 'Toplum & Ekonomi', en: 'Society & Economy', de: 'Gesellschaft & Wirtschaft', fr: 'Société & Économie', ar: 'المجتمع والاقتصاد' } },
  { kind: 'row', label: { tr: 'Sosyal Yapı', en: 'Social Structure', de: 'Sozialstruktur', fr: 'Structure sociale', ar: 'البنية الاجتماعية' }, value: { tr: 'Grup sayısını, aktif çatışmaları, liderlik değişikliklerini ve nüfus bölünmelerini izler. Grup rolleri (lider, savaşçı, şifacı, yaşlı, üye) ve hiyerarşi gelişimi modellenir; liderlik güç değişimleri kayıt altına alınır.', en: 'Tracks group count, active conflicts, leadership changes and population splits. Group roles (leader, warrior, healer, elder, member) and hierarchy development are modelled; leadership power shifts are recorded.', de: 'Verfolgt Gruppenanzahl, aktive Konflikte, Führungswechsel und Bevölkerungsspaltungen. Gruppenrollen (Anführer, Krieger, Heiler, Ältester, Mitglied) und Hierarchieentwicklung werden modelliert; Führungsmachtwechsel werden aufgezeichnet.', fr: "Suit le nombre de groupes, les conflits actifs, les changements de leadership et les scissions de population. Les rôles de groupe (chef, guerrier, guérisseur, aîné, membre) et le développement de la hiérarchie sont modélisés ; les changements de pouvoir du leadership sont enregistrés.", ar: 'يتتبع عدد المجموعات والصراعات النشطة وتغييرات القيادة وانقسامات السكان. يتم نمذجة أدوار المجموعة (قائد، محارب، شافٍ، شيخ، عضو) وتطور التسلسل الهرمي؛ وتُسجّل تحولات القوة القيادية.' } },
  { kind: 'row', label: { tr: 'Ekonomi', en: 'Economy', de: 'Wirtschaft', fr: 'Économie', ar: 'الاقتصاد' }, value: { tr: 'Ortalama refah düzeyini, Gini katsayısını (eşitsizlik endeksi) ve kaynak dağılım grafiğini gösterir. Takas ekonomisi; besin fazlası, altruizm geni ve işbirliği düzeyine göre dinamik olarak işler.', en: 'Shows average wealth level, Gini coefficient (inequality index) and resource distribution chart. The barter economy operates dynamically based on food surplus, the altruism gene and cooperation level.', de: 'Zeigt den durchschnittlichen Wohlstandsniveau, Gini-Koeffizient (Ungleichheitsindex) und Ressourcenverteilungsdiagramm. Die Tauschwirtschaft funktioniert dynamisch basierend auf Nahrungsüberschuss, dem Altruismusgen und dem Kooperationsniveau.', fr: "Affiche le niveau de richesse moyen, le coefficient de Gini (indice d'inégalité) et le graphique de distribution des ressources. L'économie de troc fonctionne dynamiquement selon l'excédent alimentaire, le gène d'altruisme et le niveau de coopération.", ar: 'يعرض متوسط مستوى الثروة ومعامل جيني (مؤشر عدم المساواة) ومخطط توزيع الموارد. تعمل اقتصاد المقايضة بشكل ديناميكي بناءً على فائض الغذاء وجين الإيثار ومستوى التعاون.' } },
  { kind: 'row', label: { tr: 'Hukuk & Normlar', en: 'Law & Norms', de: 'Recht & Normen', fr: 'Droit & Normes', ar: 'القانون والأعراف' }, value: { tr: 'Toplumsal normların dört evrim kademesini izler: kendiliğinden → sosyal → proto-hukuk → resmi. Aktif norm sayısı ve ihlal kayıtları ayrıntılı olarak görüntülenir.', en: 'Tracks four norm evolution stages: spontaneous → social → proto-law → formal. Active norm count and violation records are displayed in detail.', de: 'Verfolgt vier Normentwicklungsstufen: spontan → sozial → Proto-Recht → formal. Aktive Normanzahl und Verstößeaufzeichnungen werden detailliert angezeigt.', fr: "Suit quatre stades d'évolution des normes : spontané → social → proto-droit → formel. Le nombre de normes actives et les enregistrements de violations sont affichés en détail.", ar: 'يتتبع أربع مراحل لتطور الأعراف: تلقائي ← اجتماعي ← قانون بدائي ← رسمي. يُعرض عدد الأعراف النشطة وسجلات الانتهاكات بالتفصيل.' } },
  { kind: 'row', label: { tr: 'Psikoloji', en: 'Psychology', de: 'Psychologie', fr: 'Psychologie', ar: 'علم النفس' }, value: { tr: 'Nüfus mutluluk yüzdesini, bilişsel metrikleri (zeka, bilinç, esenlik, stres), Theory of Mind dağılımını ve zihinsel durum dökümünü (sakin, kaygılı, bunalımlı, yasda, heyecanlı) gösterir.', en: 'Shows population happiness percentage, cognitive metrics (intelligence, consciousness, wellbeing, stress), Theory of Mind distribution and mental state breakdown (calm, anxious, depressed, grieving, excited).', de: 'Zeigt den Bevölkerungsglücksprozentsatz, kognitive Metriken (Intelligenz, Bewusstsein, Wohlbefinden, Stress), Theory of Mind-Verteilung und Geisteszustandsaufschlüsselung (ruhig, ängstlich, deprimiert, trauernd, aufgeregt).', fr: "Affiche le pourcentage de bonheur de la population, les métriques cognitives (intelligence, conscience, bien-être, stress), la distribution de la Théorie de l'esprit et la ventilation des états mentaux (calme, anxieux, déprimé, en deuil, excité).", ar: 'يعرض نسبة سعادة السكان والمقاييس المعرفية (الذكاء والوعي والرفاهية والإجهاد) وتوزيع نظرية العقل وتفاصيل الحالة النفسية (هادئ، قلق، مكتئب، حداد، متحمس).' } },

  { kind: 'sub', text: { tr: 'Sağlık & Çevre', en: 'Health & Environment', de: 'Gesundheit & Umwelt', fr: 'Santé & Environnement', ar: 'الصحة والبيئة' } },
  { kind: 'row', label: { tr: 'Biyoloji', en: 'Biology', de: 'Biologie', fr: 'Biologie', ar: 'الأحياء' }, value: { tr: 'Ortalama yaş, cinsiyet oranı, zeka dağılımı, bilinç seviyeleri, genom aktivitesi ve yaşam evresi dağılımını (çocuk, yetişkin, yaşlı) gösterir. Genetik çeşitlilik indeksi de raporlanır.', en: 'Shows average age, sex ratio, intelligence distribution, consciousness levels, genome activity and life stage distribution (child, adult, elder). The genetic diversity index is also reported.', de: 'Zeigt Durchschnittsalter, Geschlechterverhältnis, Intelligenzverteilung, Bewusstseinsniveaus, Genomaktivität und Lebensstadienverteilung (Kind, Erwachsener, Älterer). Der Indexder genetischen Vielfalt wird ebenfalls gemeldet.', fr: "Affiche l'âge moyen, le ratio des sexes, la distribution de l'intelligence, les niveaux de conscience, l'activité génomique et la distribution des stades de vie (enfant, adulte, aîné). L'indice de diversité génétique est également rapporté.", ar: 'يعرض متوسط العمر ونسبة الجنس وتوزيع الذكاء ومستويات الوعي ونشاط الجينوم وتوزيع مراحل الحياة (طفل، بالغ، شيخ). يُبلَّغ أيضاً عن مؤشر التنوع الجيني.' } },
  { kind: 'row', label: { tr: 'Mikrobiyom & Hastalık', en: 'Microbiome & Disease', de: 'Mikrobiom & Krankheit', fr: 'Microbiome & Maladie', ar: 'الميكروبيوم والمرض' }, value: { tr: 'Aktif hastalık oranını, patojen tiplerini (bağırsak paraziti, kolera benzeri, solunum, veba benzeri, sıtma benzeri ve diğerleri) ve salgın geçmişini izler. Bağışıklık geni hastalık direncini doğrudan belirler.', en: 'Tracks active sick rate, pathogen types (intestinal parasite, cholera-like, respiratory, plague-like, malaria-like and others) and epidemic history. The immunity gene directly determines disease resistance.', de: 'Verfolgt aktive Krankheitsrate, Pathogentypen (Darmparasit, choleraähnlich, Atemwegs-, pestartig, malariaähnlich und andere) und Epidemiegeschichte. Das Immunitätsgen bestimmt direkt die Krankheitsresistenz.', fr: "Suit le taux de maladie active, les types de pathogènes (parasite intestinal, type choléra, respiratoire, type peste, type paludisme et autres) et l'historique des épidémies. Le gène d'immunité détermine directement la résistance aux maladies.", ar: 'يتتبع معدل المرض النشط وأنواع مسببات الأمراض (طفيل معوي، كوليرا، تنفسي، طاعون، ملاريا وغيرها) وتاريخ الأوبئة. يحدد جين المناعة مقاومة الأمراض مباشرةً.' } },
  { kind: 'row', label: { tr: 'Çevre', en: 'Environment', de: 'Umwelt', fr: 'Environnement', ar: 'البيئة' }, value: { tr: 'Aktif biyomu, mevcut mevsimi, hava koşullarını (yağış, nem, rüzgar hızı, UV indeksi) ve doğal afet geçmişini gösterir. Besin ve su bolluğu %0–100 arasında renk kodlu olarak sunulur.', en: 'Shows the active biome, current season, weather conditions (precipitation, humidity, wind speed, UV index) and natural disaster history. Food and water abundance are shown colour-coded between 0–100%.', de: 'Zeigt das aktive Biom, die aktuelle Jahreszeit, Wetterbedingungen (Niederschlag, Luftfeuchtigkeit, Windgeschwindigkeit, UV-Index) und Naturkatastrophengeschichte. Nahrung und Wasser werden farbkodiert zwischen 0–100% dargestellt.', fr: "Affiche le biome actif, la saison actuelle, les conditions météorologiques (précipitations, humidité, vitesse du vent, indice UV) et l'historique des catastrophes naturelles. L'abondance de nourriture et d'eau est représentée avec un code couleur de 0 à 100%.", ar: 'يعرض المنطقة الحيوية النشطة والموسم الحالي وأحوال الطقس (هطول الأمطار والرطوبة وسرعة الرياح ومؤشر الأشعة فوق البنفسجية) وتاريخ الكوارث الطبيعية. تُعرض وفرة الغذاء والماء بترميز لوني بين 0–100%.' } },

  { kind: 'sub', text: { tr: 'İzleme & Analiz', en: 'Monitoring & Analysis', de: 'Überwachung & Analyse', fr: 'Suivi & Analyse', ar: 'المراقبة والتحليل' } },
  { kind: 'row', label: { tr: 'İstatistikler', en: 'Statistics', de: 'Statistiken', fr: 'Statistiques', ar: 'الإحصاءات' }, value: { tr: 'Sürüklenebilir kayan panel. Nüfus, besin, su, mutluluk, bilinç ve dil metriklerinden seçim yaparak geçmiş verileri çizgi grafik olarak inceleyin.', en: 'A draggable floating panel. Select from population, food, water, happiness, consciousness and language metrics to inspect historical data as a line chart.', de: 'Ein ziehbares schwebendes Panel. Wählen Sie aus Bevölkerungs-, Nahrungs-, Wasser-, Glücks-, Bewusstseins- und Sprachmetriken aus, um historische Daten als Liniendiagramm zu untersuchen.', fr: "Un panneau flottant déplaçable. Sélectionnez parmi les métriques de population, nourriture, eau, bonheur, conscience et langage pour examiner les données historiques sous forme de graphique linéaire.", ar: 'لوحة عائمة قابلة للسحب. اختر من مقاييس السكان والغذاء والماء والسعادة والوعي واللغة لفحص البيانات التاريخية كمخطط خطي.' } },
  { kind: 'row', label: { tr: 'Performans', en: 'Performance', de: 'Leistung', fr: 'Performance', ar: 'الأداء' }, value: { tr: 'Warp modu durumunu, tick zamanlama metriklerini (ort./maks./min. ms), saniyedeki tick sayısını, mevcut gün ve nüfusu, ulaşılan kilometre taşlarını ve başlangıç/mevcut konum koordinatlarını gösterir.', en: 'Shows warp mode status, tick timing metrics (avg/max/min ms), ticks per second, current day and population, reached milestones, and start/current location coordinates.', de: 'Zeigt den Warp-Modus-Status, Tick-Timing-Metriken (Durchschnitt/Max/Min ms), Ticks pro Sekunde, aktuellen Tag und Bevölkerung, erreichte Meilensteine und Start-/aktuelle Standortkoordinaten.', fr: "Affiche l'état du mode warp, les métriques de timing des ticks (moy/max/min ms), les ticks par seconde, le jour actuel et la population, les jalons atteints et les coordonnées de départ/actuelles.", ar: 'يعرض حالة وضع الوارب ومقاييس توقيت التكات (متوسط/أقصى/أدنى بالمللي ثانية) والتكات في الثانية واليوم الحالي والسكان والمعالم المحققة وإحداثيات الموقع البادئ والحالي.' } },
  { kind: 'row', label: { tr: 'Anlar', en: 'Moments', de: 'Momente', fr: 'Moments', ar: 'اللحظات' }, value: { tr: 'Simülasyon tarihindeki önemli olayları anlık fotoğraflarla belgeler. Her an; ikon, renk, başlık, açıklama ve zaman damgasıyla kataloglanır.', en: 'Documents important events in simulation history as snapshots. Each moment is catalogued with an icon, colour, title, description and timestamp.', de: 'Dokumentiert wichtige Ereignisse in der Simulationsgeschichte als Schnappschüsse. Jeder Moment wird mit einem Symbol, einer Farbe, einem Titel, einer Beschreibung und einem Zeitstempel katalogisiert.', fr: "Documente les événements importants de l'histoire de la simulation sous forme de captures. Chaque moment est catalogué avec une icône, une couleur, un titre, une description et un horodatage.", ar: 'يُوثّق الأحداث المهمة في تاريخ المحاكاة كلقطات فورية. تُفهرس كل لحظة بأيقونة ولون وعنوان ووصف وطابع زمني.' } },
  { kind: 'row', label: { tr: 'Rapor', en: 'Report', de: 'Bericht', fr: 'Rapport', ar: 'التقرير' }, value: { tr: 'JSON veya PDF formatında kapsamlı araştırma raporu ihraç eder. Nüfus istatistikleri, zaman çizelgeleri, göç güzergahları, ölüm istatistikleri ve soy ağacı verileri dahildir.', en: 'Exports a comprehensive research report in JSON or PDF format. Includes population statistics, timelines, migration paths, death statistics and genealogy data.', de: 'Exportiert einen umfassenden Forschungsbericht im JSON- oder PDF-Format. Enthält Bevölkerungsstatistiken, Zeitpläne, Migrationspfade, Sterbestatistiken und Stammbaumdaten.', fr: "Exporte un rapport de recherche complet au format JSON ou PDF. Comprend des statistiques de population, des chronologies, des chemins de migration, des statistiques de mortalité et des données généalogiques.", ar: 'يُصدّر تقرير بحثي شاملاً بصيغة JSON أو PDF. يشمل إحصاءات السكان والجداول الزمنية ومسارات الهجرة وإحصاءات الوفاة وبيانات الأنساب.' } },

  // ── 5. OLAY AKIŞI ─────────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'V.  Olay Akışı', en: 'V.  Event Feed', de: 'V.  Ereignisfeed', fr: "V.  Flux d'événements", ar: 'V.  تدفق الأحداث' } },
  { kind: 'bullet', text: { tr: 'Doğum, ölüm, teknoloji keşfi, gruplar arası çatışma, salgın, inanç oluşumu, kültürel gelişim, sanat keşfi, astronomi gözlemi, göç ve hukuki norm ilanı dahil 10+ kategoride olaylar canlı yayınlanır.', en: 'Events in 10+ categories are broadcast live: birth, death, technology discovery, inter-group conflict, epidemic, belief formation, cultural development, art discovery, astronomy observation, migration and legal norm announcement.', de: 'Ereignisse in 10+ Kategorien werden live übertragen: Geburt, Tod, Technologieentdeckung, Gruppenkonflikt, Epidemie, Glaubensbildung, kulturelle Entwicklung, Kunstentdeckung, Astronomiebeobachtung, Migration und Rechtsnormankündigung.', fr: "Les événements dans plus de 10 catégories sont diffusés en direct : naissance, mort, découverte technologique, conflit intergroupe, épidémie, formation des croyances, développement culturel, découverte artistique, observation astronomique, migration et annonce de norme juridique.", ar: 'تُبث أحداث في أكثر من 10 فئات مباشرةً: ولادة ووفاة واكتشاف تقنية وصراع بين المجموعات ووباء وتكوّن معتقد وتطور ثقافي واكتشاف فني ومراقبة فلكية وهجرة وإعلان معيار قانوني.' } },
  { kind: 'bullet', text: { tr: 'Olaylar önem düzeyine (yüksek / orta / düşük) ve kategoriye göre renk kodludur; filtre ve arama özellikleriyle arşivden geçmiş olaylar kolayca sorgulanabilir.', en: 'Events are colour-coded by importance (high / medium / low) and category; filter and search features allow easy querying of past events from the archive.', de: 'Ereignisse sind nach Wichtigkeit (hoch / mittel / niedrig) und Kategorie farbkodiert; Filter- und Suchfunktionen ermöglichen einfache Abfragen vergangener Ereignisse aus dem Archiv.', fr: "Les événements sont codés par couleur selon l'importance (haute / moyenne / faible) et la catégorie ; les fonctions de filtre et de recherche permettent d'interroger facilement les événements passés dans les archives.", ar: 'الأحداث مرمّزة بالألوان وفق الأهمية (عالية/متوسطة/منخفضة) والفئة؛ وتتيح ميزتا التصفية والبحث الاستعلام السهل عن الأحداث الماضية من الأرشيف.' } },

  // ── 6. HİPOTEZ & ANALİZ ──────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'VI.  Hipotez Testi & Yapay Zeka Analizi', en: 'VI.  Hypothesis Testing & AI Analysis', de: 'VI.  Hypothesentests & KI-Analyse', fr: 'VI.  Test d\'hypothèse & Analyse IA', ar: 'VI.  اختبار الفرضيات وتحليل الذكاء الاصطناعي' } },
  { kind: 'row', label: { tr: 'Hipotez Testi', en: 'Hypothesis Test', de: 'Hypothesentest', fr: "Test d'hypothèse", ar: 'اختبار الفرضية' }, value: { tr: 'Önceden tanımlı veya tamamen özel hipotezler girebilirsiniz; sistem bunları gerçek simülasyon verisiyle sınar ve güven yüzdesi ile %95 güven aralığı döndürür. Adem & Havva temel metrikleri (bilinç, Theory of Mind, sözcük dağarcığı, teknoloji sayısı, sanat formu sayısı) doğrudan görüntülenir.', en: 'Enter predefined or fully custom hypotheses; the system tests them against live simulation data and returns a confidence percentage with 95% confidence intervals. Core Adam & Eve metrics (consciousness, Theory of Mind, vocabulary size, technology count, art form count) are displayed directly.', de: 'Geben Sie vordefinierte oder vollständig benutzerdefinierte Hypothesen ein; das System testet sie anhand von Live-Simulationsdaten und gibt einen Vertrauensprozentsatz mit 95%-Konfidenzintervallen zurück. Kern-Adam-&-Eva-Metriken (Bewusstsein, Theory of Mind, Vokabulargröße, Technologieanzahl, Kunstformanzahl) werden direkt angezeigt.', fr: "Entrez des hypothèses prédéfinies ou entièrement personnalisées ; le système les teste sur des données de simulation en direct et renvoie un pourcentage de confiance avec des intervalles de confiance à 95%. Les métriques fondamentales Adam & Ève (conscience, Théorie de l'esprit, taille du vocabulaire, nombre de technologies, nombre de formes d'art) sont affichées directement.", ar: 'أدخل فرضيات محددة مسبقاً أو مخصصة بالكامل؛ يختبرها النظام مقابل بيانات المحاكاة الحية ويُعيد نسبة ثقة مع فترات ثقة 95%. تُعرض المقاييس الأساسية لآدم وحواء (الوعي ونظرية العقل وحجم المفردات وعدد التقنيات وعدد أشكال الفن) مباشرةً.' } },
  { kind: 'row', label: { tr: 'BOLD Yapay Zeka Asistanı', en: 'BOLD AI Assistant', de: 'BOLD KI-Assistent', fr: 'Assistant IA BOLD', ar: 'مساعد BOLD للذكاء الاصطناعي' }, value: { tr: 'Hazır sorulardan seçebilir veya serbest metin girebilirsiniz. Asistan canlı simülasyon istatistikleri ve olay verilerini okuyarak bağlama özel yanıtlar üretir; simülasyonunuzu bilimsel perspektiften değerlendirir.', en: 'Choose from preset questions or enter free text. The assistant reads live simulation statistics and event data to produce context-specific answers and evaluate your simulation from a scientific perspective.', de: 'Wählen Sie aus vordefinierten Fragen oder geben Sie freien Text ein. Der Assistent liest Live-Simulationsstatistiken und Ereignisdaten, um kontextspezifische Antworten zu liefern und Ihre Simulation aus wissenschaftlicher Perspektive zu bewerten.', fr: "Choisissez parmi des questions prédéfinies ou entrez du texte libre. L'assistant lit les statistiques de simulation en direct et les données d'événements pour produire des réponses spécifiques au contexte et évaluer votre simulation d'un point de vue scientifique.", ar: 'اختر من الأسئلة المعدّة مسبقاً أو أدخل نصاً حراً. يقرأ المساعد إحصاءات المحاكاة الحية وبيانات الأحداث لإنتاج إجابات خاصة بالسياق وتقييم محاكاتك من منظور علمي.' } },

  // ── 7. ARIA ASİSTANI ──────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'VII.  ARIA Sesli Asistanı', en: 'VII.  ARIA Voice Assistant', de: 'VII.  ARIA Sprachassistent', fr: 'VII.  Assistant vocal ARIA', ar: 'VII.  مساعد ARIA الصوتي' } },
  { kind: 'bullet', text: { tr: 'ARIA, simülasyon sayfasındaki sesli ve yazılı yapay zeka asistanıdır. Nüfus sayısı, mevcut yıl, tüm keşiflerin listesi ve herhangi bir paneli açma komutlarına anında yanıt verir.', en: 'ARIA is the voice and text AI assistant on the simulation page. It responds instantly to population count queries, current year, full discovery lists and commands to open any panel.', de: 'ARIA ist der Sprach- und Text-KI-Assistent auf der Simulationsseite. Es antwortet sofort auf Bevölkerungszahlanfragen, aktuelles Jahr, vollständige Entdeckungslisten und Befehle zum Öffnen beliebiger Panels.', fr: "ARIA est l'assistant IA vocal et textuel sur la page de simulation. Il répond instantanément aux requêtes de nombre de population, à l'année en cours, aux listes complètes de découvertes et aux commandes d'ouverture de panneaux.", ar: 'ARIA هو المساعد الذكي الصوتي والنصي في صفحة المحاكاة. يستجيب فورياً لاستعلامات عدد السكان والسنة الحالية وقوائم الاكتشافات الكاملة وأوامر فتح أي لوحة.' } },
  { kind: 'bullet', text: { tr: 'Simülasyon sihirbazı sırasında da rehberlik eder: özellik ayarı adımlarında yardımcı olur ve mevcut özelliğin değerini sesli komutla değiştirebilirsiniz.', en: 'It also guides you through the simulation wizard: it assists with trait-setting steps and you can change the current trait value using voice commands.', de: 'Es begleitet Sie auch durch den Simulationsassistenten: Es hilft bei den Merkmalseinstellungsschritten und Sie können den aktuellen Merkmalswert mit Sprachbefehlen ändern.', fr: "Il vous guide également à travers l'assistant de simulation : il aide lors des étapes de configuration des traits et vous pouvez modifier la valeur du trait actuel à l'aide de commandes vocales.", ar: 'ترشدك أيضاً خلال معالج المحاكاة: تساعد في خطوات إعداد السمات ويمكنك تغيير قيمة السمة الحالية باستخدام أوامر صوتية.' } },

  // ── 8. TANRI MODU ─────────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'VIII.  Tanrı Modu — Harici Müdahale', en: 'VIII.  God Mode — External Intervention', de: 'VIII.  Gott-Modus — Externe Intervention', fr: 'VIII.  Mode Dieu — Intervention externe', ar: 'VIII.  وضع الإله — التدخل الخارجي' } },
  { kind: 'note', text: { tr: 'Tanrı modu müdahaleleri doğal hipotez koşularından bağımsız olarak değerlendirilmelidir. Bu modun kullanıldığı simülasyonlar bilimsel karşılaştırma amacıyla ayrı tutulmalıdır.', en: 'God mode interventions must be evaluated separately from natural hypothesis runs. Simulations using this mode should be kept separate for scientific comparison purposes.', de: 'Gottesmodus-Eingriffe müssen getrennt von natürlichen Hypothesenläufen bewertet werden. Simulationen, die diesen Modus verwenden, sollten für wissenschaftliche Vergleichszwecke separat gehalten werden.', fr: "Les interventions du mode Dieu doivent être évaluées séparément des exécutions d'hypothèses naturelles. Les simulations utilisant ce mode doivent être gardées séparées à des fins de comparaison scientifique.", ar: 'يجب تقييم تدخلات وضع الإله بشكل منفصل عن تشغيلات الفرضية الطبيعية. يجب الاحتفاظ بالمحاكاة التي تستخدم هذا الوضع منفصلة لأغراض المقارنة العلمية.' } },
  { kind: 'row', label: { tr: 'Doğal Afetler', en: 'Natural Disasters', de: 'Naturkatastrophen', fr: 'Catastrophes naturelles', ar: 'الكوارث الطبيعية' }, value: { tr: 'Deprem, sel, kuraklık, salgın, yanardağ ve meteor tetiklenebilir. Her afetin şiddeti ve etki yarıçapı bağımsız olarak ayarlanabilir.', en: 'Earthquake, flood, drought, epidemic, volcano and meteor can be triggered. Magnitude and impact radius can be configured independently for each disaster.', de: 'Erdbeben, Überschwemmung, Dürre, Seuche, Vulkan und Meteor können ausgelöst werden. Stärke und Auswirkungsradius können für jede Katastrophe unabhängig konfiguriert werden.', fr: "Tremblement de terre, inondation, sécheresse, épidémie, volcan et météore peuvent être déclenchés. L'ampleur et le rayon d'impact peuvent être configurés indépendamment pour chaque catastrophe.", ar: 'يمكن تفعيل زلزال وفيضان وجفاف ووباء وبركان ونيزك. يمكن ضبط الحجم ونصف قطر التأثير بشكل مستقل لكل كارثة.' } },
  { kind: 'row', label: { tr: 'Bireysel Müdahaleler', en: 'Individual Interventions', de: 'Individuelle Eingriffe', fr: 'Interventions individuelles', ar: 'التدخلات الفردية' }, value: { tr: 'Seçilen bir bireye +50 yıl ömür verilebilir veya anında ölüm uygulanabilir. "Bireyle Konuş" özelliği, o bireyin dil evrim kademesine göre uyarlanmış, sözcük dağarcığından türetilen bir yanıt üretir.', en: 'A selected individual can be granted +50 years of lifespan or instant death. The "Speak to individual" feature generates a response derived from that individual\'s vocabulary, adapted to their language evolution stage.', de: 'Einem ausgewählten Individuum können +50 Jahre Lebenserwartung oder sofortiger Tod gewährt werden. Die "Mit Individuum sprechen" Funktion erzeugt eine Antwort aus dem Vokabular des Individuums, angepasst an seine Sprachentwicklungsstufe.', fr: "Un individu sélectionné peut recevoir +50 ans d'espérance de vie ou une mort instantanée. La fonction « Parler à l'individu » génère une réponse dérivée du vocabulaire de cet individu, adaptée à son stade d'évolution linguistique.", ar: 'يمكن منح فرد محدد +50 سنة من العمر أو الموت الفوري. تولّد ميزة "التحدث مع الفرد" استجابة مشتقة من مفردات ذلك الفرد ومتكيفة مع مرحلة تطوره اللغوي.' } },
  { kind: 'row', label: { tr: 'Karantina Modu', en: 'Quarantine Mode', de: 'Quarantänemodus', fr: 'Mode quarantaine', ar: 'وضع الحجر الصحي' }, value: { tr: 'Aktif edildiğinde tüm doğal afetler askıya alınır. Çevre değişkenini sabitleyerek kontrollü genetik veya sosyal gözlem deneyleri yürütmek için kullanılabilir.', en: 'When active, all natural disasters are suspended. Can be used to run controlled genetic or social observation experiments by fixing the environmental variable.', de: 'Wenn aktiv, werden alle Naturkatastrophen ausgesetzt. Kann verwendet werden, um kontrollierte genetische oder soziale Beobachtungsexperimente durch Fixierung der Umweltvariable durchzuführen.', fr: "Quand actif, toutes les catastrophes naturelles sont suspendues. Peut être utilisé pour mener des expériences d'observation génétique ou sociale contrôlées en fixant la variable environnementale.", ar: 'عند التنشيط تُعلَّق جميع الكوارث الطبيعية. يمكن استخدامه لإجراء تجارب مراقبة جينية أو اجتماعية خاضعة للرقابة عن طريق تثبيت المتغير البيئي.' } },

  // ── 9. ZAMAN MAKİNESİ ─────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'IX.  Zaman Makinesi', en: 'IX.  Time Machine', de: 'IX.  Zeitmaschine', fr: 'IX.  Machine à remonter le temps', ar: 'IX.  آلة الزمن' } },
  { kind: 'bullet', text: { tr: 'İstediğiniz herhangi bir anda manuel kontrol noktası kaydedebilirsiniz. Simülasyon ayrıca her 365 günde bir otomatik kayıt alır; bu kayıtlar kontrol noktası listesinde ayrı olarak gösterilir.', en: 'You can save a manual checkpoint at any moment. The simulation also auto-saves every 365 days; these saves appear separately in the checkpoint list.', de: 'Sie können jederzeit einen manuellen Prüfpunkt speichern. Die Simulation erstellt außerdem alle 365 Tage automatisch eine Sicherung; diese werden separat in der Prüfpunktliste angezeigt.', fr: "Vous pouvez sauvegarder un point de contrôle manuel à tout moment. La simulation effectue également une sauvegarde automatique tous les 365 jours ; ces sauvegardes apparaissent séparément dans la liste des points de contrôle.", ar: 'يمكنك حفظ نقطة تفتيش يدوية في أي لحظة. تقوم المحاكاة أيضاً بالحفظ التلقائي كل 365 يوم؛ وتظهر هذه الحفظات بشكل منفصل في قائمة نقاط التفتيش.' } },
  { kind: 'bullet', text: { tr: 'Her kontrol noktasında yıl, gün ve nüfus bilgisi görünür. İstediğiniz noktaya tıkladığınızda simülasyon tam olarak o andaki durumuna geri yüklenir. Farklı senaryolar için aynı kontrol noktasından birden fazla kez çıkış yapabilirsiniz.', en: 'Each checkpoint shows year, day and population. Clicking a checkpoint restores the simulation to its exact state at that point. You can branch from the same checkpoint multiple times for different scenarios.', de: 'Jeder Prüfpunkt zeigt Jahr, Tag und Bevölkerung. Ein Klick auf einen Prüfpunkt stellt die Simulation in ihrem genauen Zustand zu diesem Zeitpunkt wieder her. Sie können denselben Prüfpunkt mehrfach für verschiedene Szenarien verzweigen.', fr: "Chaque point de contrôle affiche l'année, le jour et la population. Cliquer sur un point de contrôle restaure la simulation à son état exact à ce moment. Vous pouvez brancher depuis le même point de contrôle plusieurs fois pour différents scénarios.", ar: 'تُظهر كل نقطة تفتيش السنة واليوم والسكان. النقر يُعيد المحاكاة إلى حالتها الدقيقة في تلك النقطة. يمكنك التفرع من نفس نقطة التفتيش عدة مرات لسيناريوهات مختلفة.' } },

  // ── 10. İPUÇLARI ──────────────────────────────────────────────────────────
  { kind: 'h', text: { tr: 'X.  Stratejik İpuçları', en: 'X.  Strategic Tips', de: 'X.  Strategische Tipps', fr: 'X.  Conseils stratégiques', ar: 'X.  نصائح استراتيجية' } },
  { kind: 'bullet', text: { tr: 'İlk 180 gün kritik hayatta kalma dönemidir. Besin ve su bolluğunun yüksek olduğu bir biyom seçin; tropikal veya ılıman bölgeler başlangıç için daha güvenlidir. İlk kurucunun yaşını 20–30 arasında tutmak üreme penceresini uzatır.', en: 'The first 180 days are the critical survival period. Choose a biome with high food and water abundance; tropical or temperate regions are safer for starting out. Keeping the first founder\'s age between 20–30 extends the reproductive window.', de: 'Die ersten 180 Tage sind die kritische Überlebensperiode. Wählen Sie ein Biom mit hoher Nahrung und Wasserüberfluss; tropische oder gemäßigte Regionen sind sicherer für den Einstieg. Das Alter des ersten Gründers zwischen 20–30 zu halten, verlängert das Fortpflanzungsfenster.', fr: "Les 180 premiers jours sont la période de survie critique. Choisissez un biome avec une grande abondance de nourriture et d'eau ; les régions tropicales ou tempérées sont plus sûres. Maintenir l'âge du premier fondateur entre 20 et 30 ans prolonge la fenêtre reproductive.", ar: 'أول 180 يوماً هي فترة البقاء الحرجة. اختر منطقة حيوية بوفرة غذاء وماء عالية؛ المناطق الاستوائية أو المعتدلة أكثر أماناً. إبقاء عمر المؤسس الأول بين 20-30 يمدد نافذة الإنجاب.' } },
  { kind: 'bullet', text: { tr: 'Bilinç, dil ve teknoloji gelişimi yüzyıllar alır. ×20 veya ×100 ile çalışarak ilk medeniyet sıçramalarını hızlıca izleyin; kritik bir olay öncesinde hızı düşürüp ayrıntıları gerçek zamanlı gözlemleyin.', en: 'Consciousness, language and technology development takes centuries. Run at ×20 or ×100 to quickly watch the first civilisation leaps; reduce speed before critical events to observe details in real time.', de: 'Bewusstsein, Sprache und Technologieentwicklung dauert Jahrhunderte. Laufen Sie mit ×20 oder ×100, um die ersten Zivilisationssprünge schnell zu beobachten; reduzieren Sie die Geschwindigkeit vor kritischen Ereignissen, um Details in Echtzeit zu beobachten.', fr: "Le développement de la conscience, du langage et de la technologie prend des siècles. Exécutez à ×20 ou ×100 pour observer rapidement les premiers sauts civilisationnels ; réduisez la vitesse avant les événements critiques pour observer les détails en temps réel.", ar: 'تطوير الوعي واللغة والتكنولوجيا يستغرق قروناً. اعمل بسرعة ×20 أو ×100 لمشاهدة قفزات الحضارة الأولى بسرعة؛ اخفض السرعة قبل الأحداث الحرجة لمراقبة التفاصيل في الوقت الفعلي.' } },
  { kind: 'bullet', text: { tr: 'Zeka ve Merak özelliklerini yüksek tutmak teknoloji ve astronomi keşiflerini belirgin şekilde hızlandırır. Bağışıklık düşük tutulursa nüfus salgınlara karşı savunmasız kalır; bir salgın tüm nüfusu silebilir.', en: 'Keeping Intelligence and Curiosity high noticeably accelerates technology and astronomy discoveries. A low Immunity trait leaves the population vulnerable to epidemics; a single outbreak can wipe out the entire population.', de: 'Intelligenz und Neugier hoch zu halten beschleunigt Technologie- und Astronomieentdeckungen merklich. Ein niedriges Immunitätsmerkmal lässt die Bevölkerung anfällig für Epidemien; ein einziger Ausbruch kann die gesamte Population auslöschen.', fr: "Maintenir l'Intelligence et la Curiosité élevées accélère notablement les découvertes technologiques et astronomiques. Un trait d'Immunité faible laisse la population vulnérable aux épidémies ; une seule épidémie peut décimer toute la population.", ar: 'الحفاظ على الذكاء والفضول مرتفعَين يُسرّع بشكل ملحوظ اكتشافات التكنولوجيا والفلك. تُبقي سمة المناعة المنخفضة السكان عُرضةً للأوبئة؛ وقد تمحو فاشية واحدة السكان بأكملهم.' } },
  { kind: 'bullet', text: { tr: 'Sanat formları yalnızca besin fazlası en az %20 olduğunda ortaya çıkabilir. Uzun süreli kıtlık kültürel gelişimi tamamen durdurur; bu nedenle kaynak yönetimi kültürel evrim için de kritiktir.', en: 'Art forms can only emerge when food surplus is at least 20%. Prolonged scarcity completely halts cultural development; resource management is therefore critical for cultural evolution too.', de: 'Kunstformen können nur entstehen, wenn der Nahrungsüberschuss mindestens 20% beträgt. Anhaltende Knappheit stoppt die kulturelle Entwicklung vollständig; Ressourcenmanagement ist daher auch für die kulturelle Evolution kritisch.', fr: "Les formes d'art ne peuvent émerger que lorsque l'excédent alimentaire est d'au moins 20%. Une pénurie prolongée arrête complètement le développement culturel ; la gestion des ressources est donc également critique pour l'évolution culturelle.", ar: 'لا يمكن ظهور أشكال الفن إلا عندما يكون فائض الغذاء 20% على الأقل. يُوقف الشح المطوّل التطور الثقافي بالكامل؛ لذا فإن إدارة الموارد حيوية أيضاً للتطور الثقافي.' } },
  { kind: 'bullet', text: { tr: 'Zaman Makinesini düzenli kullanın: geri dönülemez bir afet veya nüfus çöküşü öncesinde kontrol noktası kaydetmek farklı senaryoları karşılaştırmanızı ve determinizm sorularını test etmenizi sağlar.', en: 'Use the Time Machine regularly: saving a checkpoint before an irreversible disaster or population collapse lets you compare different scenarios and test determinism questions.', de: 'Nutzen Sie die Zeitmaschine regelmäßig: Das Speichern eines Prüfpunkts vor einer unumkehrbaren Katastrophe oder einem Bevölkerungszusammenbruch ermöglicht es Ihnen, verschiedene Szenarien zu vergleichen und Determinismusfragen zu testen.', fr: "Utilisez régulièrement la Machine à remonter le temps : sauvegarder un point de contrôle avant une catastrophe irréversible ou un effondrement de population vous permet de comparer différents scénarios et de tester des questions de déterminisme.", ar: 'استخدم آلة الزمن بانتظام: حفظ نقطة تفتيش قبل كارثة لا رجعة فيها أو انهيار سكاني يتيح لك مقارنة سيناريوهات مختلفة واختبار أسئلة الحتمية.' } },
];

export function menuText(lang: LangCode, key: keyof typeof MENU_TEXT): string {
  return MENU_TEXT[key][lang] ?? MENU_TEXT[key].en ?? MENU_TEXT[key].tr;
}

export function pageText(lang: LangCode, key: keyof typeof PAGE_TEXT): string {
  return PAGE_TEXT[key][lang] ?? PAGE_TEXT[key].en ?? PAGE_TEXT[key].tr;
}

export function guideText(lang: LangCode, value: Translation): string {
  return value[lang] ?? value.en ?? value.tr;
}
